const MyBlock = {
  // ŌöĆŌöĆ Identity ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  type:     'ext_my_block',   // MUST be globally unique; prefix with 'ext_' by convention
  name:     'My Block',       // display name in palette + Inspector header
  description:     'One-line summary shown in palette tooltip',
  longDescription: 'Full paragraph shown in WikiGuide block reference.',

  // ŌöĆŌöĆ Palette placement ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  // 'blocks' ŌåÆ Core Blocks, 'tools' ŌåÆ Tools & Integrations,
  // 'triggers' ŌåÆ Triggers, 'custom' ŌåÆ Custom (default for extensions)
  category: 'custom',

  bgColor: '#6366f1',   // hex ŌĆö node header colour
  icon:    ExtensionIcon,

  // ŌöĆŌöĆ Inspector fields (subBlocks) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  subBlocks: [
    { id: 'prompt',   title: 'Prompt',  type: 'long-input',  placeholder: 'Enter promptŌĆ”', required: true },
    { id: 'model',    title: 'Model',   type: 'dropdown',    options: [{ label: 'GPT-4o', id: 'gpt-4o' }] },
    { id: 'strict',   title: 'Strict',  type: 'switch',      defaultValue: false, mode: 'advanced' },
  ],

  // ŌöĆŌöĆ Port declarations ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  inputs: {
    input: { type: 'any',    description: 'Upstream data' },
  },
  outputs: {
    result: { type: 'json',  description: 'Block output' },
  },

  // ŌöĆŌöĆ Branching (optional) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  // Uncomment to add named output handles (like if_else / switch):
  // outputHandles: ['success', 'failure'],

  // ŌöĆŌöĆ Tool access (optional, for MCP/skill integration) ŌöĆŌöĆŌöĆŌöĆŌöĆ
  tools: { access: [] },
}

export default MyBlock`}),r.jsx("h4",{style:{marginTop:28},children:"Palette sub-group placement"}),r.jsxs("p",{children:["Setting ",r.jsx("code",{children:"category"})," puts the block inside the right top-level tab. To also place it inside a specific ",r.jsx("strong",{children:"sub-group"}),' (e.g. "Input", "Databases"), add its'," ",r.jsx("code",{children:"type"})," to the relevant subgroup array in ",r.jsx("code",{children:"CATEGORY_CONFIG"})," inside"," ",r.jsx("code",{children:"blocks/registry.js"}),":"]}),r.jsx(Ds,{language:"javascript",filename:"blocks/registry.js ŌĆö CATEGORY_CONFIG",children:`// Example: place 'ext_my_block' inside Core Blocks ŌåÆ Input sub-group
